INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-57f41407-moex-00232', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依據原住民保留地開發管理辦法之規定，原住民申請無償取得原住民保留地所有權之土地面積最高限 額，下列敘述何者正確？', '["依區域計畫法編定為農牧用地、養殖用地或依都市計畫法劃定為農業區、保護區並供農作、養殖或 畜牧使用土地，每人一公頃", "依區域計畫法編定為林業用地或依都市計畫法劃定為保護區並供作造林使用之土地，每人五公頃", "依法得為建築使用之土地，每戶一公頃", "原住民申請無償取得前項第一款及第二款土地得合併計算面積，其比率由中央主管機關定之。但基 於地形限制，得百分之百增加"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00233', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '目前具原住民身分之教育師資不足，依據原住民族教育法第32條，下列內容何者有誤？', '["高級中等以下學校民族教育教師培育及資格之取得，依師資培育法及其相關法規之規定辦理", "中央教育主管機關得協調師資培育之大學，辦理師資職前教育課程，提供於原住民重點學校或偏遠 地區學校實際從事族語教學工作滿四學期且現職之族語老師、族語教學支援工作人員或代理教師進 修機會", "修畢師資職前教育課程成績及格者，由師資培育之大學發給修畢師資職前教育證明書", "經甄選獲聘任為原住民重點學校或偏遠地區學校編制內合格專任教師者，應任教民族教育課程至少 三年，始得提出申請介聘"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00234', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依據原住民族基本法之規定，政府應依原住民族特性，策訂原住民族公共衛生及醫療政策，請問下列 何者非該法所述的內容？', '["將原住民族地區納入全國醫療網", "辦理原住民族健康照顧，建立完善之長期照護、緊急救護及後送體系，保障原住民健康及生命安全", "政府應補助每個部落設置幸福康復巴士", "政府應尊重原住民族傳統醫藥和保健方法，並進行研究與推廣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00235', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '政府為保障原住民族尊嚴及基本人權，依據原住民族基本法第29條規定，政府應有何作為？', '["應於國家人權法案增訂原住民族人權保障專章", "應定期發表原住民族人權報告書", "應參與聯合國人權委員會保護原住民族人權", "應於各級政府成立原住民族人權委員會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00236', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '臺灣的原住民族人口約占臺灣人口的百分之二，依照原住民族工作權保障法第12條規定，依政府採 購法得標之廠商，於國內員工總人數逾一百人者，應於履約期間僱用原住民，其人數不得低於總人數 的比例為何？', '["百分之一", "百分之二", "百分之三", "百分之五"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00237', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依據原住民族工作權保障法之規定，各級政府應設置原住民合作社輔導小組，下列何者不是輔導小組的 職責？', '["為原住民講解合作社法及相關法令", "扶助原住民符合合作社法第9條之設立行為及登記種類之規定", "原住民合作社成立後，定期追蹤輔導合作社之運作", "支持原住民合作社的行銷通路"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00238', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '政府應依原住民群體工作習性，輔導原住民設立各種性質之原住民合作社。原住民合作社指原住民社 員需超過社員總人數比例為？', '["百分之九十以上者", "百分之八十以上者", "百分之七十以上者", "百分之五十以上者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00239', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依據原住民族基本法之規定，政府應成立財團法人原住民族文化事業基金會，下列有關其設立目的之 敘述，何者正確？', '["應保障原住民族傳播及媒體近用權", "因應開辦原住民族電視台之需要", "應落實原住民族教育", "應落實原住民族轉型正義"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00240', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依據原住民保留地禁伐補償條例，原住民保留地經劃定為禁伐區域者，其具原住民身分之所有權人或 合法使用權人，得申請禁伐補償，自民國106年起，每年每公頃的補償金額為多少元？', '["一萬元", "二萬元", "三萬元", "五萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00241', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', 'Acatjumpedfromthecornerinthedarkandgavemea_____.', '["respect", "scare", "change", "square"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
